configuration.jsScript:
var spo2 = msg.spo2;
var rr   = msg.respiratory_rate;
var temp = msg.temperature;
var hr   = msg.heart_rate;
var sys  = msg.systolic_bp;
var dia  = msg.diastolic_bp;

var prev = metadata.ss_status_label;
if (prev == null || prev == "") {
    prev = "UNKNOWN";
}

var label = "STABLE";

// ============================================================
// HIERARKI STATUS (urutan = prioritas)
// ============================================================

// --- 1. CRITICAL ---
// SpO2 sangat rendah ATAU napas sangat cepat
if (spo2 != null && ((spo2 <= 88 && prev != "CRITICAL") || (spo2 < 90 && prev == "CRITICAL"))) {
    label = "CRITICAL";
}
else if (rr != null && ((rr > 30 && prev != "CRITICAL") || (rr > 28 && prev == "CRITICAL"))) {
    label = "CRITICAL";
}

// --- 2. HYPOXIA ---
// SpO2 rendah + napas cepat (belum separah CRITICAL)
else if (spo2 != null && rr != null &&
    ((spo2 < 92 && rr >= 24 && prev != "HYPOXIA") ||
     (prev == "HYPOXIA" && spo2 < 94))) {
    label = "HYPOXIA";
}

// --- 3. FEVER ---
// Suhu tinggi + detak jantung cepat
else if (temp != null && hr != null && temp >= 38.0 && hr >= 85) {
    label = "FEVER";
}

// --- 4. HYPERTENSION ---
// Tekanan darah tinggi
else if ((sys != null && sys >= 140) || (dia != null && dia >= 90)) {
    label = "HYPERTENSION";
}

// --- 5. HYPOTENSION ---
// Tekanan darah terlalu rendah (bahaya syok)
else if (sys != null && sys < 90) {
    label = "HYPOTENSION";
}

// --- 6. ARRHYTHMIA ---
// Detak jantung terlalu lambat (bradikardi) atau terlalu cepat (takikardi)
// tanpa penjelasan dari kondisi lain (demam/hipoksia sudah dihandle di atas)
else if (hr != null && (hr < 50 || hr > 110)) {
    label = "ARRHYTHMIA";
}

// --- 7. UNSTABLE ---
// Tanda awal perburukan: salah satu parameter mulai keluar batas normal
else if (function() {
    var count = 0;
    if (rr   != null && rr   > 20)                   count++;
    if (spo2 != null && spo2 >= 92 && spo2 < 95)     count++;
    if (temp != null && temp >= 37.5 && temp < 38.0) count++;
    if (sys  != null && sys  >= 130 && sys  < 140)   count++;
    if (dia  != null && dia  >= 85  && dia  < 90)    count++;
    return count >= 2; // minimal 2 parameter bermasalah
}()) {
    label = "UNSTABLE";
}

// --- 8. STABLE ---
// Semua parameter dalam batas normal
else if (
    hr   != null && hr   >= 60  && hr   <= 100 &&
    spo2 != null && spo2 >= 95  &&
    rr   != null && rr   >= 12  && rr   <= 20  &&
    temp != null && temp >= 36.1 && temp <= 37.5 &&
    (sys == null || (sys >= 90 && sys < 130)) &&
    (dia == null || (dia >= 60 && dia < 85))
) {
    label = "STABLE";
}

// ============================================================
// FILTER PERUBAHAN & KIRIM
// ============================================================
if (label != prev) {
    metadata.newStatusLabel = label;
    metadata.currentTemp    = temp != null ? temp + "°C"       : "N/A";
    metadata.currentSpO2    = spo2 != null ? spo2 + "%"        : "N/A";
    metadata.currentHR      = hr   != null ? hr   + " bpm"     : "N/A";
    metadata.currentRR      = rr   != null ? rr   + " x/menit" : "N/A";
    metadata.deviceName     = metadata.deviceName  || "Unknown Device";
    metadata.patientName    = metadata.patientName || metadata.deviceName;

    var newMsg = { "status_label": label };
    return { msg: newMsg, metadata: metadata, msgType: 'POST_ATTRIBUTES_REQUEST' };
}

return { msg: null };

configuration.tbelScript:
var s = metadata.newStatusLabel;
if (s == null) return false;
if (s == "STABLE" || s == "UNKNOWN" || s == "UNSTABLE") return false;
return true;

var current = metadata.newStatusLabel;
var prev = metadata.ss_status_label;

if (prev == null) return true;
if (current == prev) return false;
return true;

configuration.userPrompt:
Status       : ${newStatusLabel}
SpO2         : ${currentSpO2}
Heart Rate   : ${currentHR}
Temperature  : ${currentTemp}
Respiratory  : ${currentRR} breaths/min

Analyze this patient's vital signs.

configuration.jsScript:
try {
    var aiResult = msg;
    metadata.aiAnalisis    = aiResult.analisis    || "Analysis unavailable";
    metadata.aiRekomendasi = aiResult.rekomendasi || "Contact medical staff";
} catch(e) {
    metadata.aiAnalisis    = "Analysis unavailable";
    metadata.aiRekomendasi = "Contact medical staff";
}

return {msg: msg, metadata: metadata, msgType: msgType};
